if (! function_exists('text_frequency_counter')) {
    function text_frequency_counter($text, $mode = null, $case_sensitive = null, $min_freq = null, $stop_words = null, $max_results = null)
    {
        $mode = $mode ?? 'word';
        $case_sensitive = $case_sensitive ?? false;
        $min_freq = $min_freq ?? 1;
        $max_results = $max_results ?? 50;

        $text = (string)$text;
        if (empty(trim($text))) { return json_encode(['error' => 'Empty text']); }

        $items = [];

        switch ($mode) {
            case 'char':
                $chars = [];
                $len = mb_strlen($text);
                for ($i = 0; $i < $len; $i++) {
                    $c = mb_substr($text, $i, 1);
                    if (!ctype_space($c)) {
                        $chars[] = $case_sensitive ? $c : mb_strtolower($c);
                    }
                }
                $items = $chars;
                break;
                
            case 'bigram':
                $words = preg_split('/\s+/', trim($text));
                if (!$case_sensitive) { $words = array_map('strtolower', $words); }
                for ($i = 0; $i < count($words) - 1; $i++) {
                    $items[] = $words[$i] . ' ' . $words[$i + 1];
                }
                break;
                
            case 'trigram':
                $words = preg_split('/\s+/', trim($text));
                if (!$case_sensitive) { $words = array_map('strtolower', $words); }
                for ($i = 0; $i < count($words) - 2; $i++) {
                    $items[] = $words[$i] . ' ' . $words[$i + 1] . ' ' . $words[$i + 2];
                }
                break;
                
            default: // word
                $words = preg_split('/\s+/', trim($text));
                $words = array_filter($words, function($w) { return $w !== ''; });
                if (!$case_sensitive) { $words = array_map('strtolower', $words); }
                // Remove punctuation from start/end of words
                $words = array_map(function($w) { return trim($w, '.,!?;:()[]{}""\'\'"'); }, $words);
                $words = array_filter($words, function($w) { return $w !== ''; });
                $items = $words;
                break;
        }

        // Build frequency table
        $freq = [];
        foreach ($items as $item) {
            if (!isset($freq[$item])) { $freq[$item] = 0; }
            $freq[$item]++;
        }

        // Apply stop word filter
        if (!empty($stop_words)) {
            $stopList = array_map('trim', explode(',', $stop_words));
            if (!$case_sensitive) { $stopList = array_map('strtolower', $stopList); }
            foreach ($stopList as $stop) {
                unset($freq[$stop]);
            }
        }

        // Filter by min_freq
        $freq = array_filter($freq, function($f) use ($min_freq) { return $f >= $min_freq; });

        // Sort descending by frequency, then alphabetically for ties
        arsort($freq);

        $total = count($items);
        $total_types = count($freq);
        $results = [];
        $count = 0;
        foreach ($freq as $item => $f) {
            if ($count >= $max_results) { break; }
            $results[] = [
                'item' => $item,
                'frequency' => $f,
                'percentage' => round(($f / $total) * 100, 2)
            ];
            $count++;
        }

        return json_encode([
            'ok' => true,
            'mode' => $mode,
            'total_items' => $total,
            'unique_types' => $total_types,
            'results' => $results
        ]);
    }
